python3 -c "
import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-hitl-multi-outcome-routing/LeaveRequestBpmn/LeaveRequestBpmn.bpmn')
root = tree.getroot()

ns = {
    'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
    'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
    'uipath': 'http://uipath.org/schema/bpmn',
}

# 1. Root tag
print('Root tag:', root.tag)

# 2. BPMNDiagram
diags = root.findall('bpmndi:BPMNDiagram', ns)
print('BPMNDiagram count:', len(diags))
shapes = root.findall('.//bpmndi:BPMNShape', ns)
edges = root.findall('.//bpmndi:BPMNEdge', ns)
print('Shapes:', len(shapes), '  Edges:', len(edges))

# 3. Collect all declared IDs
all_ids = {el.get('id') for el in root.iter() if el.get('id')}
print('Declared IDs count:', len(all_ids))

# Check refs resolve
errors = []
for el in root.iter():
    for attr in ('sourceRef','targetRef','attachedToRef','bpmnElement','default'):
        val = el.get(attr)
        if val and val not in all_ids:
            errors.append(f'Unresolved {attr}={val!r} on {el.get(\"id\",el.tag)}')
if errors:
    for e in errors: print('REF ERROR:', e)
else:
    print('All refs resolve OK')

# 4. XOR gateway conditions
for gw in root.findall('.//bpmn:exclusiveGateway', ns):
    default = gw.get('default')
    outgoing = [c.text for c in gw.findall('bpmn:outgoing', ns)]
    print(f'XOR gw {gw.get(\"id\")}: outgoing={outgoing}, default={default!r}')
    for fid in outgoing:
        if fid == default: continue
        flows = root.findall(f'.//bpmn:sequenceFlow[@id=\"{fid}\"]', ns)
        if not flows:
            errors.append(f'Flow {fid} not found')
        else:
            cond = flows[0].find('bpmn:conditionExpression', ns)
            if cond is None:
                errors.append(f'Non-default flow {fid} missing conditionExpression')
            else:
                print(f'  Flow {fid} condition: {cond.text!r}')

# 5. No activity/event with >1 incoming
for el in root.iter():
    inc = el.findall('bpmn:incoming', ns)
    if len(inc) > 1:
        errors.append(f'{el.get(\"id\")} has {len(inc)} incoming flows (fake join)')

# 7. vars.* references resolve
var_ids = {v.get('id') for v in root.findall('.//uipath:inputOutput', ns)}
print('Variable IDs:', var_ids)
import re
for el in root.iter():
    for attr, val in el.attrib.items():
        for ref in re.findall(r'vars\.(\w+)', val):
            if ref not in var_ids:
                errors.append(f'vars.{ref} not declared (in {el.get(\"id\",el.tag)})')
    if el.text:
        for ref in re.findall(r'vars\.(\w+)', el.text):
            if ref not in var_ids:
                errors.append(f'vars.{ref} not declared (text)')

if errors:
    print('ERRORS:')
    for e in errors: print(' ', e)
else:
    print('VALID - all structural checks pass')
